mapper.select:
/*
	ezGrader 팀원에 부여된 초기 점수 조회
	ForumEzGraderDAO.listTeamMeberInitScore
*/
SELECT A.STD_ID AS evalTrgtUserId
	, ROUND(B.EVL_TOT_SCR / #{evalScore} * 100) AS evalScore
FROM TB_LMS_DSCS_PTCP A
LEFT JOIN MTL_EVL_RSLT B
	ON A.TEAM_ID = B.RLTN_TEAM_CD
	AND A.STD_ID = B.EVLTEE_ID
	AND B.ASMT_MTL_EVL_RSLT_ID = #{evalCd}
WHERE A.TEAM_ID = #{rltnTeamCd}

	AND A.STD_ID = #{evalTrgtUserId}

mapper.insert:
/* 팀원 모두에게 문항별 평가한 내용을 토대로 총 평가점수 부여 ForumEzGraderDAO.initStdScoreToAllTeamMember */ INSERT INTO TB_LMS_DSCS_PTCP ( TEAM_ID , DSCS_ID , STD_ID , SCR , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM ) SELECT A.TEAM_ID , #{forumCd} , A.STD_ID
, ROUND(B.EVL_TOT_SCR / #{evalScore} * 100)
, 0
, #{rgtrId} , FN_DTTM() , #{rgtrId} , FN_DTTM() FROM TB_LMS_TEAM_MBR A LEFT JOIN MTL_EVL_RSLT B ON A.TEAM_ID = B.RLTN_TEAM_CD AND A.STD_ID = B.EVLTEE_ID AND B.ASMT_MTL_EVL_RSLT_ID = #{evalCd} WHERE A.TEAM_ID = #{rltnTeamCd}
AND A.STD_ID = #{evalTrgtUserId}
ON DUPLICATE KEY UPDATE
STD_ID = A.STD_ID, SCR = #{evalScore}
STD_ID = A.STD_ID, SCR = 0

mapper.update:
/*
	토론 참여 유저(미참여자 포함)에 평가점수 부여
	ForumEzGraderDAO.updateJoinUserScore
*/
INSERT INTO TB_LMS_DSCS_PTCP (
	STD_ID
	, DSCS_ID
	, SCR
	, EVLYN
	, DELYN
	, RGTR_ID
	, FRST_INQ_DTTM
	, MDFR_ID
	, MOD_DTTM
) VALUES (
	#{evalTrgtUserId}
	, #{forumCd}
	, #{evalScore}
	, 'Y'
	, 'N'
	, #{rgtrId}
	, FN_DTTM()
	, #{rgtrId}
	, FN_DTTM()
)
ON DUPLICATE KEY UPDATE
	SCR = #{evalScore}
	, EVLYN = #{evalYn}
	, MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()

mapper.delete:
/*
	팀원 총 평가점수  삭제
	ForumEzGraderDAO.deleteTeamStdScore
*/
DELETE FROM TB_LMS_DSCS_PTCP
WHERE TEAM_ID = #{rltnTeamCd}

	AND STD_ID = #{evalTrgtUserId}

mapper.insert:
/*
	팀원 모두에게 총  평가점수 부여
	ForumEzGraderDAO.insertStdScoreToAllTeamMember 
*/
INSERT INTO TB_LMS_DSCS_PTCP (
	TEAM_ID
	, DSCS_ID
	, STD_ID
	, SCR
	, RGTR_ID
	, FRST_INQ_DTTM
	, MDFR_ID
	, MOD_DTTM
)
SELECT
	A.TEAM_ID
	, #{forumCd}
	, A.STD_ID
	, #{evalScore}
	, #{rgtrId}
	, FN_DTTM()
	, #{rgtrId}
	, FN_DTTM()
FROM TB_LMS_TEAM_MBR A
WHERE 1 = 1

	AND TEAM_ID = #{rltnTeamCd}
	AND STD_ID = #{evalTrgtUserId}


	AND TEAM_ID = #{rltnTeamCd}

ON DUPLICATE KEY UPDATE

	STD_ID = #{evalTrgtUserId}, SCR = #{evalScore}


	STD_ID = A.STD_ID, SCR = #{evalScore}

/*
	팀원 모두에게 평가점수 등록
	ForumEzGraderDAO.insertEvalRsltToAllTeamMember 
*/
INSERT INTO MTL_EVL_RSLT (
	MTL_EVL_CD
	, ASMT_MTL_EVL_RSLT_ID
	, RLTN_TEAM_CD
	, EVLTR_ID
	, EVLTEE_ID
	, EVL_DTTM
	, QSTN_NOS
	, EVL_SCRS
	, EVL_TOT_SCR
	, EVL_CTS
	, EVL_STSCD
	, RGTR_ID
	, FRST_INQ_DTTM
	, MDFR_ID
	, MOD_DTTM
)
SELECT FN_NEW_ID('MUT')
	, #{evalCd}
	, A.TEAM_ID
	, #{rgtrId}
	, A.STD_ID
	, FN_DTTM()
	, #{qstnNos}
	, #{evalScores}
	, #{evalTotal}
	, #{evalCts}
	, #{evalStatusCd}
	, #{rgtrId}
	, FN_DTTM()
	, #{rgtrId}
	, FN_DTTM()
FROM TB_LMS_TEAM_STD A
WHERE TEAM_ID = #{rltnTeamCd}
